import json
import ast

# Load the list of businesses that received reviews in 2018
business_refs_2018_data = locals().get('var_functions.query_db:50', [])
business_refs_2018 = []

if isinstance(business_refs_2018_data, list):
    for item in business_refs_2018_data:
        business_refs_2018.append(item.get('business_ref', ''))

# Convert business_ref to business_id format
business_ids_2018 = set()
for ref in business_refs_2018:
    if ref.startswith('businessref_'):
        num = ref.replace('businessref_', '')
        business_ids_2018.add(f'businessid_{num}')

# Read the full business data
business_file_path = '.storage/var_functions.query_db:28.json'
try:
    with open(business_file_path, 'r') as f:
        all_businesses = json.load(f)
except Exception as e:
    print(f'Error: {e}')
    all_businesses = []

# Process all businesses to find parking availability
parking_count = 0
businesses_with_parking_details = []
missing_business_count = 0
found_business_ids = set()

for business in all_businesses:
    business_id = business.get('business_id')

    # Check if this business was reviewed in 2018
    if business_id in business_ids_2018:
        found_business_ids.add(business_id)
        attributes = business.get('attributes', {})

        has_business_parking = False
        has_bike_parking = False
        parking_info = {}

        # Process business parking attributes
        if isinstance(attributes, dict) and attributes != 'None':
            # Check BusinessParking
            business_parking = attributes.get('BusinessParking')
            if business_parking and business_parking != 'None':
                try:
                    parking_dict = ast.literal_eval(business_parking)
                    if isinstance(parking_dict, dict):
                        for parking_type, available in parking_dict.items():
                            if available == True:
                                has_business_parking = True
                                parking_info[parking_type] = True
                except:
                    # Fallback string check
                    if 'True' in business_parking:
                        has_business_parking = True

            # Check BikeParking
            bike_parking = attributes.get('BikeParking')
            if bike_parking == 'True':
                has_bike_parking = True

        # Count if either parking type is offered
        if has_business_parking or has_bike_parking:
            parking_count += 1
            businesses_with_parking_details.append({
                'business_id': business_id,
                'name': business.get('name'),
                'has_business_parking': has_business_parking,
                'has_bike_parking': has_bike_parking,
                'parkings': parking_info
            })

# Check for businesses not found in the business collection
missing_business_ids = business_ids_2018 - found_business_ids

print('__RESULT__:')
print(json.dumps({
    'total_businesses_reviewed_2018': len(business_ids_2018),
    'businesses_with_parking_count': parking_count,
    'businesses_found': len(found_business_ids),
    'businesses_not_found': len(missing_business_ids),
    'parking_businesses_sample': businesses_with_parking_details[:10]
}))

